onepassword:index/item:Item.description:
A 1Password Item.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as onepassword from "@1password/pulumi-onepassword";

// Example using section_map (map-based sections for direct field access)
const exampleWithMap = new onepassword.Item("example_with_map", {
    vault: "your-vault-id",
    title: "Example Item with Section Map",
    category: "login",
    sectionMap: {
        credentials: {
            fieldMap: {
                api_key: {
                    type: "CONCEALED",
                    value: "my-secret-api-key",
                },
                api_endpoint: {
                    type: "URL",
                    value: "https://api.example.com",
                },
            },
        },
        metadata: {
            fieldMap: {
                environment: {
                    type: "STRING",
                    value: "production",
                },
                created_by: {
                    type: "STRING",
                    value: "terraform",
                },
            },
        },
    },
});
// Example using section (list-based sections)
const exampleWithList = new onepassword.Item("example_with_list", {
    vault: "your-vault-id",
    title: "Example Item with Section List",
    category: "login",
    passwordRecipe: {
        length: 40,
        symbols: false,
    },
    sections: [{
        label: "Example section",
        fields: [{
            label: "Example field",
            type: "DATE",
            value: "2024-01-31",
        }],
    }],
});
